import{_ as a,o as s,c as o,ak as n}from"./chunks/framework.Dpc0wyhY.js";const h=JSON.parse('{"title":"Commands","description":"","frontmatter":{},"headers":[],"relativePath":"grindr-api/websocket/commands.md","filePath":"grindr-api/websocket/commands.md"}'),t={name:"grindr-api/websocket/commands.md"};function i(r,e,d,c,l,m){return s(),o("div",null,[...e[0]||(e[0]=[n('<h1 id="commands" tabindex="-1">Commands <a class="header-anchor" href="#commands" aria-label="Permalink to “Commands”">​</a></h1><p>WebSocket API supports commands that mimic HTTP requests.</p><p>All requests must have these fields in addition to any top-level properties specified for each request type:</p><ul><li><code>type</code> — string, command type, e.g. <code>chat.v1.message.send</code></li><li><code>ref</code> — <a href="#websocket-command-ref">WebSocket command ref</a></li><li><code>token</code> — string, <a href="/grindr-api/authentication#session-id">Session ID</a></li></ul><p>Invalid or expired tokens passed in token field cause socket closing with status code 4401.</p><h2 id="websocket-command-ref" tabindex="-1">WebSocket command ref <a class="header-anchor" href="#websocket-command-ref" aria-label="Permalink to “WebSocket command ref”">​</a></h2><p>String, required in each command.</p><p>Used to identify responses to concurrent requests.</p><p><strong>It&#39;s imperative that you use a different ref for each request, as responses seem to be cached/requests skipped.</strong> Does not have any limits on length or disallowed characters. <code>null</code> values are not allowed as input. Any other value is coerced into string.</p><h2 id="websocket-command-response" tabindex="-1">WebSocket command response <a class="header-anchor" href="#websocket-command-response" aria-label="Permalink to “WebSocket command response”">​</a></h2><p>Command response is an <a href="/grindr-api/websocket/events">event</a> sent with <code>type</code> property value being <code>[command].response</code>.</p><p>Additionally, responses have the following fields:</p><ul><li><code>status</code> — HTTP status code for this response</li><li><code>ref</code> — <a href="#websocket-command-ref">WebSocket command ref</a></li><li><code>payload</code> — object, result of request</li></ul><p>Response&#39;s <code>payload</code> usually mirrors the response of HTTP API endpoint.</p><h2 id="send-a-message-to-a-conversation-via-ws" tabindex="-1">Send a message to a conversation via WS <a class="header-anchor" href="#send-a-message-to-a-conversation-via-ws" aria-label="Permalink to “Send a message to a conversation via WS”">​</a></h2><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>chat.v1.message.send</span></span></code></pre></div><ul><li><code>payload</code> — body of <a href="/grindr-api/messaging/messages#send-a-message-to-a-conversation">Send a message to a conversation</a></li></ul><p><a href="#websocket-command-response">Response</a>:</p><p>See: <a href="/grindr-api/messaging/messages#send-a-message-to-a-conversation">HTTP API -&gt; Send a message to a conversation</a></p>',19)])])}const f=a(t,[["render",i]]);export{h as __pageData,f as default};
